import org.springframework.security.oauth2.client.OAuth2RestTemplate;
import org.springframework.security.oauth2.client.resource.OAuth2ProtectedResourceDetails;
import org.springframework.security.oauth2.config.annotation.web.configuration.EnableOAuth2Client;
import org.springframework.stereotype.Controller;
import org.springframework.ui.ModelMap;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.client.RestTemplate;

@Controller
@EnableOAuth2Client
public class Oauth2Controller {

    @RequestMapping(value = "/login", method = RequestMethod.GET)
    public String login() {
        return "login";
    }

    @RequestMapping("/")
    public String index(@RequestParam("code") String code, ModelMap model) throws Exception{

        OAuth2ProtectedResourceDetails resource = new OAuth2ProtectedResourceDetails();
        resource.setAccessTokenUri(System.getenv("ACCESS_TOKEN"));
        resource.setClientId(System.getenv("CLIENT_ID"));
        resource.setClientSecret(System.getenv("CLIENT_SECRET"));
        resource.setGrantType("authorization_code");

        OAuth2RestTemplate template = new OAuth2RestTemplate(resource);
        String token = template.getAccessToken().getValue();

        RestTemplate restTemplate = new RestTemplate();
        String userInfoUrl = System.getenv("USERINFO") + "?access_token=" + token;
        model.addAttribute("userInfo", restTemplate.getForObject(userInfoUrl, String.class));

        return "index";
    }
}

